insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('クルージング', '大型の船で航海すること。', 1002201, 10022, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('はんせん', '帆を張って風力で進む船。', 1002202, 10022, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('シップ', '「ふね」の英語読み。', 1002203, 10022, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ぎゅうにゅう', '牛がだす乳汁。そのまま飲むのはもちろん、チーズやバターなどに加工できる優れもの。', 1002300, 10023, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ミルク', '「ぎゅうにゅう」の英語読み。', 1002301, 10023, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('おちち', '「ぎゅうにゅう」のまた別の呼び方。口に出すのはちょっと恥ずかしい。', 1002302, 10023, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('エリザベス', 'エリザベスパークにいる牛の名前にしてマヒルのパートナー。', 1002303, 10023, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('チョコレート', 'カカオを加工したお菓子。２月14日に大量消費される。', 1002400, 10024, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('おかし', '通常の食事以外で食す嗜好品。', 1002401, 10024, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('あまいもの', '甘い味のするもの。疲れた時にほしくなる。', 1002402, 10024, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('カカオ', 'チョコレートの原料。含有量が多いほどビターな味わいにな\\nる。', 1002403, 10024, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ドラちゃんのこうぶつ', '味をしめたらしい。', 1002404, 10024, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('どんぐり', '硬い木の実。人が食すにはあまり適さないが、子どもの収集欲を刺激する魅惑の木の実。', 1002500, 10025, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('きのみ', '木になる実。', 1002501, 10025, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ナッツ', '硬い殻に包まれた食用の実。お菓子に入れたり酒のつまみにと色々重宝する。', 1002502, 10025, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('リンのおやつ', 'アンパンほどではないが、好きらしい。バトルのときは敵にぶつけてスタンさせる。', 1002503, 10025, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('いちご', '小さく甘酸っぱい果物。種と思われる粒々は実は果実。', 1002600, 10026, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ストロベリー', '「いちご」の英語読み。', 1002601, 10026, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ジャム', '果物を加工した食品。パンやクラッカーに塗ったり、紅茶に入れたりする。', 1002602, 10026, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('とら', '大型のネコ科の猛獣。肉食。酔っぱらいを指す言葉としても使われる。', 1002700, 10027, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('タイガー', '「とら」の英語読み。', 1002701, 10027, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ねこ', 'ネコ科の哺乳類。人間となじみの深い動物で、そのかわいさの前に人間はただただ無力。', 1002702, 10027, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('けもの', '全身を毛におおわれ、四足で歩く哺乳類。', 1002703, 10027, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('マツリのあこがれ', 'トラタイガー！', 1002704, 10027, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('むてきヒーロートラタイガー', 'マツリが憧れる正義のヒーロー。名前にツッコんではいけな\\nい。', 1002705, 10027, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ぬいぐるみ', '布を縫合し綿などを詰めて人や動物を似せて形作ったもの。', 1002800, 10028, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('うさぎ', '長い耳と短い尻尾がかわいい哺乳類。ペットとしても人気が高い。', 1002801, 10028, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('にんぎょう', '人や生き物を模ったもの。材質も様々で、玩具や観賞用、祭礼と用途は様々。', 1002802, 10028, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ラビット', '「うさぎ」の英語読み。', 1002803, 10028, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('アーサー', 'マホのぬいぐるみの一体。名称はアーサー王と円卓の騎士がモチーフ。', 1002804, 10028, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ばくだん', '爆発による熱と衝撃で対象を破壊、殺傷する兵器。超危ない。', 1002900, 10029, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ボム', '「ばくだん」の英語読み。', 1002901, 10029, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('きけんぶつ', '生物や環境に危険を及ぼす可能性のある物質。取り扱いには資格が必要になることもある。', 1002902, 10029, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('とびどうぐ', '遠くから飛ばして攻撃するタイプの武器のこと。反則的な発想やアイデアという意味で使われることもある。', 1002903, 10029, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ミソギのいたずらグッズ', '一度ちゃんと怒られた方がいい。', 1002904, 10029, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('すいか', 'ウリ科の大きな果実。緑のしま模様の皮、赤い果肉と黒い種が印象的。', 1003000, 10030, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('こだますいか', '小ぶりのスイカ。小玉といえどまあまあデカい。', 1003001, 10030, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('なつのふうぶつし', '夏の感じを表す物事。スイカの他に海や花火など。', 1003002, 10030, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('うま', 'ウマ科の大型の哺乳類。力が強く速く走れるため、家畜や競走馬としてなじみ深い。', 1003100, 10031, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ろば', 'ウマ科の哺乳類。馬に比べて小型だが力が強く労働力として重宝される。', 1003101, 10031, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ホース', '「うま」の英語読み。', 1003102, 10031, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ぱかぱか', '馬が歩く時のひづめの音。', 1003103, 10031, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('サラブレッド', '馬の種類で競走用に品種改良されたもの。', 1003104, 10031, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ムーバ', 'クランバトルに登場する馬型の魔物。', 1003105, 10031, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('いす', '腰かけるための家具。役職、地位を示す意味もある。', 1003200, 10032, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かぐ', '室内に配置して日常的に使用する道具の総称。', 1003201, 10032, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('チェア', '「いす」の英語読み。', 1003202, 10032, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ギルドハウスアイテム', 'ギルドハウスに置く家具や装飾品。豪華なデザインからユニークなものまで、そのバリエーションは非常に豊か。', 1003203, 10032, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('うみ', '陸地以外の凹所にひとつづきに水がたたえている場所。', 1003300, 10033, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かいがん', '陸地が海と接する部分。', 1003301, 10033, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ビーチ', '海辺。海水浴場として用いられることもある。ここでものを食べるとなんだかとても美味い。', 1003302, 10033, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('しおさい', '寄せてくる波が立てる音。貝殻に耳を当ててもそれっぽい音が聞こえる。', 1003303, 10033, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('すなはま', '砂ばかりの浜辺。城を建てたり埋まってみたりと楽しみ方は無限大。', 1003304, 10033, 1, 2);
