insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('やどかり', '貝殻を背負って生活する甲殻類。', 1003400, 10034, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かいがら', '貝類の外側を覆う殻。砂浜に落ちているとつい集めたくなる。', 1003401, 10034, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('こうかくるい', '硬い外骨格を持つ節足動物。エビ、カニはもちろんミジンコもこれにあたる。', 1003402, 10034, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ハーミットナイト', 'ランドソルのいたる所に現れる魔物。鎧のような見た目の通り硬くて厄介な敵。', 1003403, 10034, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ふえ', '一般的に木管楽器を指す言葉。縦笛と横笛に分けられる。', 1003500, 10035, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('リコーダー', '木管楽器の一種。チャンバラごっこに使ってはいけない。', 1003501, 10035, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かんがっき', '楽器の分類のうちのひとつ。息を吹き込み管内の空気を振動させ音を出す。', 1003502, 10035, 1, 2);
