insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ほん', '紙の束に文字や図画を印刷し製本したもの。', 1003600, 10036, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ノート', '文字や絵を書き記すための文房具。', 1003601, 10036, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('しょうせつ', '創作の物語。恋愛、歴史、ミステリーなどジャンルは多岐にわたる。', 1003602, 10036, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ブック', '「ほん」の英語読み。', 1003603, 10036, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('キャルのまどうしょ', '本なの？\u3000それとも杖なの？', 1003604, 10036, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('さかな', '魚類の一般的な呼び方。食べると頭がよくなるという噂。', 1003700, 10037, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('おさかな', '魚類の一般的な呼び方。年をとると肉より食べたくなるといわれている。', 1003701, 10037, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かつお', '魚の一種。刺身が美味い。かつおぶしなどの加工品でもおなじみ。', 1003702, 10037, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('まぐろ', '魚の一種。でかくて美味い高級魚。寿司といえばこれ。', 1003703, 10037, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('フィッシュ', '「さかな」の英語読み。', 1003704, 10037, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('うお', '「さかな」のまた別の呼び方。', 1003705, 10037, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ツリー', '樹木のこと。', 1003800, 10038, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('クリスマス', 'いつから、どうしてなのかは不明だがサンタクロースがプレゼントをくれる日。', 1003801, 10038, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('もみのき', 'クリスマスツリーに用いられる針葉樹。大きいものは40ｍにもなる。', 1003802, 10038, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('キャロル', 'クリスマスに歌われる祝歌。', 1003803, 10038, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ぼうきゃくのキャロル', 'チカとサレンディア救護院に起きた、聖なる夜の奇跡の物語。', 1003804, 10038, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('あめ', '砂糖などを煮詰め固めた菓子。', 1003900, 10039, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('キャンディ', '「あめ」の英語読み。', 1003901, 10039, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ロリポップ', '棒つきの飴。', 1003902, 10039, 1, 2);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('クロエのおやつ', '持ってるだけで絵になる。', 1003903, 10039, 1, 3);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ハンマー', '頭が金属でできた鈍器。叩かれるととても痛い。', 1004000, 10040, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('ピコピコハンマー', '頭がやわらかいじゃばらでできたおもちゃ。叩かれるとコミカルな音が鳴る。', 1004001, 10040, 1, 1);
insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('かなづち', '頭が金属でできた鈍器。叩かれるととても痛い。', 1004002, 10040, 1, 2);
