insert into v1_779dc9532ee0bf9f532e3040879db2291a26c694bfd743459e78cc8a508af0c8 values ('テレじょのやべーやつ', 'テレ女のやべーやつ。すなわち、チエルのこと。', 2006402, 20064, 1, 3);
